// 1. Sadə Promise
function prepareActor(actor) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve(`${actor} hazırdır!`);
      } else {
        reject(`${actor} gəlmədi!`);
      }
    }, 2000);
  });
}

prepareActor("Aktyor 1")
  .then(result => console.log(result))
  .catch(error => console.log(`Səhv: ${error}`));
// nəticə (ehtimala görə):
// Aktyor 1 hazırdır!
// və ya: Səhv: Aktyor 1 gəlmədi!

// 2. then və catch ilə zəncir
function setupScene() {
  return new Promise((resolve) => {
    setTimeout(() => resolve("Səhnə quruldu!"), 1500);
  });
}

setupScene()
  .then(result => {
    console.log(result);
    return prepareActor("Aktyor 2");
  })
  .then(result => console.log(result))
  .catch(error => console.log(`Səhv: ${error}`));
// nəticə:
// Səhnə quruldu!
// Aktyor 2 hazırdır! (və ya səhv)

// 3. finally: Hər halda işləyir
prepareActor("Aktyor 3")
  .then(result => console.log(result))
  .catch(error => console.log(`Səhv: ${error}`))
  .finally(() => console.log("Çəkilişə hazırlıq bitdi!"));
// nəticə: Çəkilişə hazırlıq bitdi! (hər halda görünür)

// 4. Promise.all: Bütün tapşırıqları gözləyir
Promise.all([
  prepareActor("Aktyor 4"),
  setupScene(),
  prepareActor("Aktyor 5")
])
  .then(results => console.log("Hamısı hazırdır: ", results))
  .catch(error => console.log(`Səhv: ${error}`));
// nəticə: Hamısı hazırdır: ["Aktyor 4 hazırdır!", "Səhnə quruldu!", "Aktyor 5 hazırdır!"]

// 5. Promise.race: İlk tamamlananı qaytarır
Promise.race([
  prepareActor("Aktyor 6"),
  setupScene()
])
  .then(result => console.log(`İlk hazır: ${result}`))
  .catch(error => console.log(`Səhv: ${error}`));
// nəticə: İlk hazır: Səhnə quruldu! (əgər səhnə daha tezdirsə)

// Səhv idarəetməsiz nümunə
function riskyPromise() {
  return new Promise((resolve, reject) => {
    reject("Kamera xarab oldu!");
  });
}

riskyPromise()
  .then(result => console.log(result))
  .catch(error => console.log(`Səhv: ${error}`));
// nəticə: Səhv: Kamera xarab oldu!

// Promise.all ilə uğursuzluq
Promise.all([
  prepareActor("Aktyor 7"),
  new Promise((resolve, reject) => reject("Səhnə hazır deyil!")),
  prepareActor("Aktyor 8")
])
  .then(results => console.log(results))
  .catch(error => console.log(`Səhv: ${error}`));
// nəticə: Səhv: Səhnə hazır deyil!

