// 1. Simple Promise
function prepareActor(actor) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve(`${actor} is ready!`);
      } else {
        reject(`${actor} didn’t show up!`);
      }
    }, 2000);
  });
}

prepareActor("Actor 1")
  .then(result => console.log(result))
  .catch(error => console.log(`Error: ${error}`));
// Output (depending on chance):
// Actor 1 is ready!
// or: Error: Actor 1 didn’t show up!

// 2. Chaining with then and catch
function setupScene() {
  return new Promise((resolve) => {
    setTimeout(() => resolve("Scene is set!"), 1500);
  });
}

setupScene()
  .then(result => {
    console.log(result);
    return prepareActor("Actor 2");
  })
  .then(result => console.log(result))
  .catch(error => console.log(`Error: ${error}`));
// Output:
// Scene is set!
// Actor 2 is ready! (or error)

// 3. finally: Runs regardless
function prepareActor("Actor 3")
  .then(result => console.log(result))
  .catch(error => console.log(`Error: ${error}`))
  .finally(() => console.log("Preparation for shoot completed!"));
// Output: Preparation for shoot completed! (always appears)

// 4. Promise.all: Waits for all tasks
Promise.all([
  prepareActor("Actor 4"),
  setupScene(),
  prepareActor("Actor 5")
])
  .then(results => console.log("All ready: ", results))
  .catch(error => console.log(`Error: ${error}`));
// Output: All ready: ["Actor 4 is ready!", "Scene is set!", "Actor 5 is ready!"]

// 5. Promise.race: Returns the first completed
Promise.race([
  prepareActor("Actor 6"),
  setupScene()
])
  .then(result => console.log(`First ready: ${result}`))
  .catch(error => console.log(`Error: ${error}`));
// Output: First ready: Scene is set! (if scene is faster)

// Missing error handling example
function riskyPromise() {
  return new Promise((resolve, reject) => {
    reject("Camera broke!");
  });
}

riskyPromise()
  .then(result => console.log(result))
  .catch(error => console.log(`Error: ${error}`));
// Output: Error: Camera broke!

// Promise.all failure
Promise.all([
  prepareActor("Actor 7"),
  new Promise((resolve, reject) => reject("Scene not ready!")),
  prepareActor("Actor 8")
])
  .then(results => console.log(results))
  .catch(error => console.log(`Error: ${error}`));
// Output: Error: Scene not ready!

