// 1. Простой Promise
function prepareActor(actor) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve(`${actor} готов!`);
      } else {
        reject(`${actor} не явился!`);
      }
    }, 2000);
  });
}

prepareActor("Актёр 1")
  .then(result => console.log(result))
  .catch(error => console.log(`Ошибка: ${error}`));
// Вывод (в зависимости от шанса):
// Актёр 1 готов!
// или: Ошибка: Актёр 1 не явился!

// 2. Цепочка с then и catch
function setupScene() {
  return new Promise((resolve) => {
    setTimeout(() => resolve("Сцена установлена!"), 1500);
  });
}

setupScene()
  .then(result => {
    console.log(result);
    return prepareActor("Актёр 2");
  })
  .then(result => console.log(result))
  .catch(error => console.log(`Ошибка: ${error}`));
// Вывод:
// Сцена установлена!
// Актёр 2 готов! (или ошибка)

// 3. finally: Выполняется в любом случае
prepareActor("Актёр 3")
  .then(result => console.log(result))
  .catch(error => console.log(`Ошибка: ${error}`))
  .finally(() => console.log("Подготовка к съёмкам завершена!"));
// Вывод: Подготовка к съёмкам завершена! (всегда появляется)

// 4. Promise.all: Ждёт завершения всех задач
Promise.all([
  prepareActor("Актёр 4"),
  setupScene(),
  prepareActor("Актёр 5")
])
  .then(results => console.log("Всё готово: ", results))
  .catch(error => console.log(`Ошибка: ${error}`));
// Вывод: Всё готово: ["Актёр 4 готов!", "Сцена установлена!", "Актёр 5 готов!"]

// 5. Promise.race: Возвращает первый завершённый
Promise.race([
  prepareActor("Актёр 6"),
  setupScene()
])
  .then(result => console.log(`Первый готов: ${result}`))
  .catch(error => console.log(`Ошибка: ${error}`));
// Вывод: Первый готов: Сцена установлена! (если сцена быстрее)

// Пример без обработки ошибок
function riskyPromise() {
  return new Promise((resolve, reject) => {
    reject("Камера сломалась!");
  });
}

riskyPromise()
  .then(result => console.log(result))
  .catch(error => console.log(`Ошибка: ${error}`));
// Вывод: Ошибка: Камера сломалась!

// Неудача Promise.all
Promise.all([
  prepareActor("Актёр 7"),
  new Promise((resolve, reject) => reject("Сцена не готова!")),
  prepareActor("Актёр 8")
])
  .then(results => console.log(results))
  .catch(error => console.log(`Ошибка: ${error}`));
// Вывод: Ошибка: Сцена не готова!

